import sys

input = sys.stdin.read
data = input().split()

N = int(data[0])
A = list(map(int, data[1:1 + N]))

# Compute lenL: strict increasing prefix from left
lenL = 1 if N > 0 else 0
for i in range(1, N):
    if A[i] > A[i - 1]:
        lenL += 1
    else:
        break

# Compute lenR: strict increasing chain from right (leftward increasing)
lenR = 1 if N > 0 else 0
for i in range(N - 2, -1, -1):
    if A[i] > A[i + 1]:
        lenR += 1
    else:
        break

if lenL % 2 == 1 or lenR % 2 == 1:
    print("Alice")
else:
    print("Bob")

