import sys
import math

input = sys.stdin.read
data = input().split()

index = 0
t = int(data[index])
index += 1

for _ in range(t):
    n = int(data[index])
    index += 1
    a = [int(data[index + i]) for i in range(n)]
    index += n

    cnt = [0] * 30
    for x in a:
        for b in range(30):
            if (x & (1 << b)):
                cnt[b] += 1

    g = 0
    for c in cnt:
        if c > 0:
            if g == 0:
                g = c
            else:
                g = math.gcd(g, c)

    if g == 0:
        ans = list(range(1, n + 1))
    else:
        ans = []
        i = 1
        while i * i <= g:
            if g % i == 0:
                ans.append(i)
                j = g // i
                if j != i:
                    ans.append(j)
            i += 1
        ans.sort()

    print(' '.join(map(str, ans)))

