import sys

input = sys.stdin.read
data = input().split()

t = int(data[0])
idx = 1
for _ in range(t):
    s = data[idx]
    idx += 1
    n = len(s)
    parent = list(range(n))
    rank = [0] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        px = find(x)
        py = find(y)
        if px != py:
            if rank[px] < rank[py]:
                parent[px] = py
            elif rank[px] > rank[py]:
                parent[py] = px
            else:
                parent[py] = px
                rank[px] += 1

    for i in range(n):
        if s[i] == 'E':
            union(i, (i + 1) % n)

    possible = True
    for i in range(n):
        if s[i] == 'N':
            if find(i) == find((i + 1) % n):
                possible = False
                break

    print("YES" if possible else "NO")

